import requests
import json
from pydantic import BaseModel, Field


class Tools:
    class Valves(BaseModel):
        ALPHA_VANTAGE_KEY: str = Field(
            default="", description="Free API key from alphavantage.co"
        )

    def __init__(self):
        self.valves = self.Valves()
        self.base = "https://www.alphavantage.co/query"

    def _get(self, params: dict) -> dict:
        if not self.valves.ALPHA_VANTAGE_KEY:
            raise Exception(
                "ALPHA_VANTAGE_KEY not set. Get a free key at alphavantage.co"
            )
        params["apikey"] = self.valves.ALPHA_VANTAGE_KEY
        return requests.get(self.base, params=params).json()

    # ─────────────────────────────────────────
    # TECHNICAL INDICATORS
    # ─────────────────────────────────────────

    def get_rsi(self, ticker: str, interval: str = "daily", period: int = 14) -> str:
        """
        Get RSI (Relative Strength Index). Above 70 = overbought, below 30 = oversold.
        interval: 1min, 5min, 15min, 30min, 60min, daily, weekly, monthly
        """
        try:
            data = self._get(
                {
                    "function": "RSI",
                    "symbol": ticker,
                    "interval": interval,
                    "time_period": period,
                    "series_type": "close",
                }
            )
            latest = list(data.get("Technical Analysis: RSI", {}).items())[:10]
            return json.dumps([{"date": d, "RSI": v["RSI"]} for d, v in latest])
        except Exception as e:
            return f"Error: {e}"

    def get_macd(self, ticker: str, interval: str = "daily") -> str:
        """Get MACD (Moving Average Convergence Divergence) indicator."""
        try:
            data = self._get(
                {
                    "function": "MACD",
                    "symbol": ticker,
                    "interval": interval,
                    "series_type": "close",
                }
            )
            latest = list(data.get("Technical Analysis: MACD", {}).items())[:10]
            return json.dumps(
                [
                    {
                        "date": d,
                        "MACD": v["MACD"],
                        "signal": v["MACD_Signal"],
                        "hist": v["MACD_Hist"],
                    }
                    for d, v in latest
                ]
            )
        except Exception as e:
            return f"Error: {e}"

    def get_sma(self, ticker: str, period: int = 50, interval: str = "daily") -> str:
        """Get SMA (Simple Moving Average). Common periods: 20, 50, 200."""
        try:
            data = self._get(
                {
                    "function": "SMA",
                    "symbol": ticker,
                    "interval": interval,
                    "time_period": period,
                    "series_type": "close",
                }
            )
            latest = list(data.get("Technical Analysis: SMA", {}).items())[:10]
            return json.dumps([{"date": d, "SMA": v["SMA"]} for d, v in latest])
        except Exception as e:
            return f"Error: {e}"

    def get_ema(self, ticker: str, period: int = 50, interval: str = "daily") -> str:
        """Get EMA (Exponential Moving Average). Common periods: 9, 20, 50, 200."""
        try:
            data = self._get(
                {
                    "function": "EMA",
                    "symbol": ticker,
                    "interval": interval,
                    "time_period": period,
                    "series_type": "close",
                }
            )
            latest = list(data.get("Technical Analysis: EMA", {}).items())[:10]
            return json.dumps([{"date": d, "EMA": v["EMA"]} for d, v in latest])
        except Exception as e:
            return f"Error: {e}"

    def get_bollinger_bands(
        self, ticker: str, period: int = 20, interval: str = "daily"
    ) -> str:
        """Get Bollinger Bands: upper, middle, lower bands."""
        try:
            data = self._get(
                {
                    "function": "BBANDS",
                    "symbol": ticker,
                    "interval": interval,
                    "time_period": period,
                    "series_type": "close",
                }
            )
            latest = list(data.get("Technical Analysis: BBANDS", {}).items())[:10]
            return json.dumps(
                [
                    {
                        "date": d,
                        "upper": v["Real Upper Band"],
                        "middle": v["Real Middle Band"],
                        "lower": v["Real Lower Band"],
                    }
                    for d, v in latest
                ]
            )
        except Exception as e:
            return f"Error: {e}"

    def get_stochastic(self, ticker: str, interval: str = "daily") -> str:
        """Get Stochastic Oscillator (STOCH). Above 80 = overbought, below 20 = oversold."""
        try:
            data = self._get(
                {"function": "STOCH", "symbol": ticker, "interval": interval}
            )
            latest = list(data.get("Technical Analysis: STOCH", {}).items())[:10]
            return json.dumps(
                [
                    {"date": d, "SlowK": v["SlowK"], "SlowD": v["SlowD"]}
                    for d, v in latest
                ]
            )
        except Exception as e:
            return f"Error: {e}"

    def get_adx(self, ticker: str, period: int = 14, interval: str = "daily") -> str:
        """Get ADX (Average Directional Index). Measures trend strength. Above 25 = strong trend."""
        try:
            data = self._get(
                {
                    "function": "ADX",
                    "symbol": ticker,
                    "interval": interval,
                    "time_period": period,
                }
            )
            latest = list(data.get("Technical Analysis: ADX", {}).items())[:10]
            return json.dumps([{"date": d, "ADX": v["ADX"]} for d, v in latest])
        except Exception as e:
            return f"Error: {e}"

    def get_cci(self, ticker: str, period: int = 20, interval: str = "daily") -> str:
        """Get CCI (Commodity Channel Index). Above 100 = overbought, below -100 = oversold."""
        try:
            data = self._get(
                {
                    "function": "CCI",
                    "symbol": ticker,
                    "interval": interval,
                    "time_period": period,
                }
            )
            latest = list(data.get("Technical Analysis: CCI", {}).items())[:10]
            return json.dumps([{"date": d, "CCI": v["CCI"]} for d, v in latest])
        except Exception as e:
            return f"Error: {e}"

    def get_atr(self, ticker: str, period: int = 14, interval: str = "daily") -> str:
        """Get ATR (Average True Range). Measures market volatility."""
        try:
            data = self._get(
                {
                    "function": "ATR",
                    "symbol": ticker,
                    "interval": interval,
                    "time_period": period,
                }
            )
            latest = list(data.get("Technical Analysis: ATR", {}).items())[:10]
            return json.dumps([{"date": d, "ATR": v["ATR"]} for d, v in latest])
        except Exception as e:
            return f"Error: {e}"

    def get_obv(self, ticker: str, interval: str = "daily") -> str:
        """Get OBV (On Balance Volume). Measures buying/selling pressure using volume."""
        try:
            data = self._get(
                {"function": "OBV", "symbol": ticker, "interval": interval}
            )
            latest = list(data.get("Technical Analysis: OBV", {}).items())[:10]
            return json.dumps([{"date": d, "OBV": v["OBV"]} for d, v in latest])
        except Exception as e:
            return f"Error: {e}"

    def get_aroon(self, ticker: str, period: int = 14, interval: str = "daily") -> str:
        """Get Aroon indicator. Measures trend direction and strength."""
        try:
            data = self._get(
                {
                    "function": "AROON",
                    "symbol": ticker,
                    "interval": interval,
                    "time_period": period,
                }
            )
            latest = list(data.get("Technical Analysis: AROON", {}).items())[:10]
            return json.dumps(
                [
                    {
                        "date": d,
                        "Aroon_Up": v["Aroon Up"],
                        "Aroon_Down": v["Aroon Down"],
                    }
                    for d, v in latest
                ]
            )
        except Exception as e:
            return f"Error: {e}"

    def get_all_technicals(self, ticker: str) -> str:
        """Get a complete technical analysis summary: RSI, MACD, SMA 50/200, Bollinger Bands, Stochastic, ADX."""
        results = {}
        try:
            results["RSI_14"] = json.loads(self.get_rsi(ticker))[:3]
            results["MACD"] = json.loads(self.get_macd(ticker))[:3]
            results["SMA_50"] = json.loads(self.get_sma(ticker, 50))[:3]
            results["SMA_200"] = json.loads(self.get_sma(ticker, 200))[:3]
            results["EMA_20"] = json.loads(self.get_ema(ticker, 20))[:3]
            results["Bollinger_Bands"] = json.loads(self.get_bollinger_bands(ticker))[
                :3
            ]
            results["Stochastic"] = json.loads(self.get_stochastic(ticker))[:3]
            results["ADX"] = json.loads(self.get_adx(ticker))[:3]
            results["ATR"] = json.loads(self.get_atr(ticker))[:3]
        except Exception as e:
            results["error"] = str(e)
        return json.dumps(results)

    # ─────────────────────────────────────────
    # PRICE DATA
    # ─────────────────────────────────────────

    def get_intraday(self, ticker: str, interval: str = "5min") -> str:
        """
        Get intraday OHLCV price data.
        interval: 1min, 5min, 15min, 30min, 60min
        """
        try:
            data = self._get(
                {
                    "function": "TIME_SERIES_INTRADAY",
                    "symbol": ticker,
                    "interval": interval,
                    "outputsize": "compact",
                }
            )
            key = f"Time Series ({interval})"
            series = data.get(key, {})
            return json.dumps(
                [
                    {
                        "datetime": dt,
                        "open": v["1. open"],
                        "high": v["2. high"],
                        "low": v["3. low"],
                        "close": v["4. close"],
                        "volume": v["5. volume"],
                    }
                    for dt, v in list(series.items())[:20]
                ]
            )
        except Exception as e:
            return f"Error: {e}"

    def get_daily(self, ticker: str) -> str:
        """Get daily OHLCV price data (last 100 days)."""
        try:
            data = self._get(
                {
                    "function": "TIME_SERIES_DAILY",
                    "symbol": ticker,
                    "outputsize": "compact",
                }
            )
            series = data.get("Time Series (Daily)", {})
            return json.dumps(
                [
                    {
                        "date": dt,
                        "open": v["1. open"],
                        "high": v["2. high"],
                        "low": v["3. low"],
                        "close": v["4. close"],
                        "volume": v["5. volume"],
                    }
                    for dt, v in list(series.items())[:30]
                ]
            )
        except Exception as e:
            return f"Error: {e}"

    def get_weekly(self, ticker: str) -> str:
        """Get weekly OHLCV price data."""
        try:
            data = self._get({"function": "TIME_SERIES_WEEKLY", "symbol": ticker})
            series = data.get("Weekly Time Series", {})
            return json.dumps(
                [
                    {
                        "date": dt,
                        "open": v["1. open"],
                        "high": v["2. high"],
                        "low": v["3. low"],
                        "close": v["4. close"],
                        "volume": v["5. volume"],
                    }
                    for dt, v in list(series.items())[:20]
                ]
            )
        except Exception as e:
            return f"Error: {e}"

    # ─────────────────────────────────────────
    # FUNDAMENTALS
    # ─────────────────────────────────────────

    def get_company_overview(self, ticker: str) -> str:
        """Get full company fundamental data from Alpha Vantage."""
        try:
            return json.dumps(self._get({"function": "OVERVIEW", "symbol": ticker}))
        except Exception as e:
            return f"Error: {e}"

    def get_earnings(self, ticker: str) -> str:
        """Get annual and quarterly EPS earnings history."""
        try:
            data = self._get({"function": "EARNINGS", "symbol": ticker})
            return json.dumps(
                {
                    "annual_earnings": data.get("annualEarnings", [])[:5],
                    "quarterly_earnings": data.get("quarterlyEarnings", [])[:8],
                }
            )
        except Exception as e:
            return f"Error: {e}"

    def get_income_statement(self, ticker: str) -> str:
