            return json.dumps(
                {
                    "annual": data.get("annualReports", [])[:3],
                    "quarterly": data.get("quarterlyReports", [])[:4],
                }
            )
        except Exception as e:
            return f"Error: {e}"

    def get_balance_sheet(self, ticker: str) -> str:
        """Get annual and quarterly balance sheets."""
        try:
            data = self._get({"function": "BALANCE_SHEET", "symbol": ticker})
            return json.dumps(
                {
                    "annual": data.get("annualReports", [])[:3],
                    "quarterly": data.get("quarterlyReports", [])[:4],
                }
            )
        except Exception as e:
            return f"Error: {e}"

    def get_cash_flow(self, ticker: str) -> str:
        """Get annual and quarterly cash flow statements."""
        try:
            data = self._get({"function": "CASH_FLOW", "symbol": ticker})
            return json.dumps(
                {
                    "annual": data.get("annualReports", [])[:3],
                    "quarterly": data.get("quarterlyReports", [])[:4],
                }
            )
        except Exception as e:
            return f"Error: {e}"

    # ─────────────────────────────────────────
    # FOREX & CRYPTO
    # ─────────────────────────────────────────

    def get_forex_rate(self, from_currency: str, to_currency: str) -> str:
        """Get real-time forex exchange rate. e.g. from_currency=USD, to_currency=EUR"""
        try:
            data = self._get(
                {
                    "function": "CURRENCY_EXCHANGE_RATE",
                    "from_currency": from_currency,
                    "to_currency": to_currency,
                }
            )
            info = data.get("Realtime Currency Exchange Rate", {})
            return json.dumps(
                {
                    "pair": f"{from_currency}/{to_currency}",
                    "rate": info.get("5. Exchange Rate"),
                    "bid": info.get("8. Bid Price"),
                    "ask": info.get("9. Ask Price"),
                    "last_updated": info.get("6. Last Refreshed"),
                }
            )
        except Exception as e:
            return f"Error: {e}"

    def get_crypto_rating(self, symbol: str) -> str:
        """
        Get crypto fundamental rating and metrics from Alpha Vantage.
        symbol: BTC, ETH, SOL, BNB, XRP, ADA, DOGE
        """
        try:
            data = self._get({"function": "CRYPTO_RATING", "symbol": symbol})
            return json.dumps(data)
        except Exception as e:
            return f"Error: {e}"

    # ─────────────────────────────────────────
    # NEWS & SENTIMENT
    # ─────────────────────────────────────────

    def get_news_sentiment(self, tickers: str = "", topics: str = "") -> str:
        """
        Get news and sentiment analysis for stocks.
        tickers: comma separated e.g. 'AAPL,TSLA'
        topics: comma separated e.g. 'technology,earnings,ipo'
        Available topics: blockchain, earnings, ipo, mergers_and_acquisitions,
        financial_markets, economy_fiscal, economy_monetary, economy_macro,
        energy_transportation, finance, life_sciences, manufacturing,
        real_estate, retail_wholesale, technology
        """
        try:
            params = {"function": "NEWS_SENTIMENT"}
            if tickers:
                params["tickers"] = tickers
            if topics:
                params["topics"] = topics
            params["limit"] = 10
            data = self._get(params)
            return json.dumps(
                [
                    {
                        "title": a.get("title"),
                        "source": a.get("source"),
                        "published": a.get("time_published"),
                        "sentiment_label": a.get("overall_sentiment_label"),
                        "sentiment_score": a.get("overall_sentiment_score"),
                        "url": a.get("url"),
                        "summary": a.get("summary"),
                    }
                    for a in data.get("feed", [])
                ]
            )
        except Exception as e:
            return f"Error: {e}"

    def get_top_gainers_losers(self) -> str:
        """Get today's top gaining and losing stocks plus most actively traded."""
        try:
            data = self._get({"function": "TOP_GAINERS_LOSERS"})
            return json.dumps(
                {
                    "top_gainers": data.get("top_gainers", [])[:10],
                    "top_losers": data.get("top_losers", [])[:10],
                    "most_active": data.get("most_actively_traded", [])[:10],
                }
            )
        except Exception as e:
            return f"Error: {e}"

    def search_symbol(self, query: str) -> str:
        """Search for a stock ticker symbol by company name. e.g. 'Apple', 'Tesla', 'Microsoft'"""
        try:
            data = self._get({"function": "SYMBOL_SEARCH", "keywords": query})
            return json.dumps(
                [
                    {
                        "symbol": m["1. symbol"],
                        "name": m["2. name"],
                        "type": m["3. type"],
                        "region": m["4. region"],
                        "currency": m["8. currency"],
                    }
                    for m in data.get("bestMatches", [])
                ]
            )
        except Exception as e:
            return f"Error: {e}"

    def get_market_status(self) -> str:
        """Get current open/closed status of major global stock exchanges."""
        try:
            data = self._get({"function": "MARKET_STATUS"})
            return json.dumps(data.get("markets", []))
        except Exception as e:
            return f"Error: {e}"
